actions.script:
import groovy.json.JsonSlurper

def slurper = new JsonSlurper()
def globalRef = ec.resource.getLocationReference("component://moqui-ai/registry.json")
def globalRegistry = globalRef.getExists() ? slurper.parse(globalRef.openStream()) : [macros:[:]]

def effectiveMacros = [:]
effectiveMacros.putAll(globalRegistry.macros ?: [:])

if (app) {
    def localRef = ec.resource.getLocationReference("component://${app}/registry.json")
    if (localRef.getExists()) {
        def localRegistry = slurper.parse(localRef.openStream())
        if (localRegistry.macros) {
            effectiveMacros.putAll(localRegistry.macros)
        }
    }
}

context.registry = [macros: effectiveMacros]

def slurper = new groovy.json.JsonSlurper()
def ref = ec.resource.getLocationReference("component://moqui-ai/registry/ui-macros.json")
context.macros = ref.getExists() ? slurper.parse(ref.openStream()) : [:]
